# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

import secrets
import datetime
from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config["SQLALCHEMY_DATABASE_URI"] = "sqlite:///reset.db"
app.config["SQLALCHEMY_TRACK_MODIFICATIONS"] = False
db = SQLAlchemy(app)

class PasswordReset(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(64), nullable=False, unique=True)
    created_at = db.Column(db.DateTime, default=datetime.datetime.utcnow)

@app.before_first_request
def create_tables():
    db.create_all()

@app.route("/reset-password", methods=["POST"])
def reset_password():
    data = request.get_json()
    if not data or "email" not in data:
        return jsonify({"error": "Email is required"}), 400

    email = data["email"]
    token = secrets.token_urlsafe(32)
    
    new_reset = PasswordReset(email=email, token=token)
    db.session.add(new_reset)
    db.session.commit()
    
    reset_link = f"http://your-domain.com/reset/{token}"
    print(f"Sending reset link to {email}: {reset_link}")
    
    return jsonify({"message": "Reset link sent", "reset_link": reset_link}), 200

if __name__ == "__main__":
    app.run(debug=True)